// src/modules/auth/auth.service.ts
var createUserIntoDB = async (payload) => {
  const { name, email, password, role } = payload;
  const allowedRoles = ["CUSTOMER", "PROVIDER"];
  if (role && !allowedRoles.includes(role)) {
    throw new Error("Invalid role. Only CUSTOMER or PROVIDER is allowed");
  }
  const isExistUser = await prisma.user.findUnique({
    where: {
      email
    }
  });
  if (isExistUser) {
    throw new Error("User already exist with this email");
  }
  const hashPassword = await bcrypt.hash(
    password,
    Number(config_default.bcrypt_salt_rounds)
  );
  const createdUser = await prisma.user.create({
    data: {
      name,
      email,
      password: hashPassword,
      role
    },
    omit: {
      password: true
    }
  });
  return createdUser;
};
var loginUserIntoDB = async (email, password) => {
  const user = await prisma.user.findUnique({
    where: {
      email
    }
  });
  if (!user) {
    throw new Error("User not found! Please register.");
  }
  if (user.status === "SUSPENDED") {
    throw new Error("Your account has been suspended. Please contact support!");
  }
  const matchPassword = await bcrypt.compare(password, user?.password);
  if (!matchPassword) {
    throw new Error("Password is incorect!");
  }
  const jwtPayload = {
    id: user.id,
    email: user.email,
    role: user.role
  };
  const accessToken = jwtUtils.createToken(
    jwtPayload,
    config_default.jwt_access_secret,
    config_default.jwt_access_expires_in
  );
  const refreshToken = jwtUtils.createToken(
    jwtPayload,
    config_default.jwt_refresh_secret,
    config_default.jwt_refresh_expires_in
  );
  return { accessToken, refreshToken };
};
var getCurrentUserFromDB = async (userId) => {
  const user = await prisma.user.findUnique({
    where: {
      id: userId
    },
    omit: {
      password: true
    }
  });
  if (!user) {
    throw new Error("User not found");
  }
  return user;
};
