var createUser = catchAsync(
  async (req, res, next) => {
    const payload = req.body;
    if (!payload.name || !payload.email || !payload.password) {
      throw new Error("name, email and password are required");
    }
    const result = await authServices.createUserIntoDB(payload);
    sendResponse_default(res, { message: "Register successfully!", data: result }, 201);
  }
);
var loginUser = catchAsync(
  async (req, res, next) => {
    const { email, password } = req.body;
    if (!email || !password) {
      throw new Error("Email and Password are required.");
    }
    const { accessToken, refreshToken } = await authServices.loginUserIntoDB(
      email,
      password
    );
    res.cookie("accessToken", accessToken, {
      httpOnly: true,
      secure: false,
      sameSite: "none",
      maxAge: 1e3 * 60 * 60 * 24
      // 24 hour or 1 day
    });
    res.cookie("refreshToken", refreshToken, {
      httpOnly: true,
      secure: false,
      sameSite: "none",
      maxAge: 1e3 * 60 * 60 * 24 * 7
      // 7 day
    });
    sendResponse_default(res, {
      message: "User logged in successfully!",
      data: { accessToken, refreshToken }
    });
  }
);
