var createCategoryIntoDB = async (categoryName) => {
  const normalizedCategoryName = categoryName.trim().toLowerCase();
  const category = await prisma.category.findUnique({
    where: {
      name: normalizedCategoryName
    }
  });
  if (category) {
    throw new Error(`Category ${categoryName} is already exist`);
  }
  const createdCategory = await prisma.category.create({
    data: {
      name: normalizedCategoryName
    }
  });
  return createdCategory;
};
var getCategoriesFromDB = async () => {
  const categories = await prisma.category.findMany({
    orderBy: {
      createdAt: "desc"
    }
  });
  return categories;
};
var updateCategoryIntoDB = async (name, id) => {
  const category = await prisma.category.findUnique({
    where: {
      id
    }
  });
  if (!category) {
    throw new Error("Category not found!");
  }
  if (category.name.toLowerCase() === name.toLowerCase()) {
    throw new Error(`Category ${name} already updated.`);
  }
  const existingCategory = await prisma.category.findUnique({
    where: {
      name
    }
  });
  if (existingCategory && existingCategory.id !== id) {
    throw new Error(`Category '${name}' already exists.`);
  }
  const updatedCategory = await prisma.category.update({
    where: {
      id
    },
    data: {
      name
    }
  });
  return updatedCategory;
};
var deleteCategoryFromDB = async (id) => {
  const category = await prisma.category.findUnique({
    where: {
      id
    }
  });
  if (!category) {
    throw new Error("Category not found!");
  }
  const gearCount = await prisma.gearItem.count({
    where: {
      categoryId: id
    }
  });
  if (gearCount > 0) {
    throw new Error("Cannot delete category because it contains gear items.");
  }
  await prisma.category.delete({
    where: {
      id
    }
  });
};
