var creatOrderIntoDB = async (payload, customerId) => {
  const { gearItemId, quantity, startDate, endDate } = payload;
  const convertedStartDate = new Date(startDate);
  const convertedEndDate = new Date(endDate);
  if (isNaN(convertedStartDate.getTime()) || isNaN(convertedEndDate.getTime())) {
    throw new Error("Invalid date format");
  }
  if (convertedStartDate >= convertedEndDate) {
    throw new Error("End date must be after start date");
  }
  if (quantity < 1) {
    throw new Error("Quantity must be at least 1");
  }
  const gear = await prisma.gearItem.findUnique({
    where: {
      id: gearItemId
    }
  });
  if (!gear) {
    throw new Error("Gear item not found.");
  }
  if (gear.stock < quantity) {
    throw new Error("Insufficient stock");
  }
  const totalDays = Math.ceil(
    (convertedEndDate.getTime() - convertedStartDate.getTime()) / (1e3 * 60 * 60 * 24)
  );
  const totalAmount = Number(gear.rentalPrice) * quantity * totalDays;
  const result = await prisma.$transaction(async (tx) => {
    const createdOrder = await tx.rentalOrder.create({
      data: {
        gearItemId,
        customerId,
        quantity,
        totalAmount,
        startDate: convertedStartDate,
        endDate: convertedEndDate
      }
    });
    await tx.gearItem.update({
      where: {
        id: gearItemId
      },
      data: {
        stock: {
          decrement: quantity
        }
      }
    });
    return createdOrder;
  });
  return result;
};
